sql:
SELECT athlete_id, athlete_name, team_id, personal_best_10k
FROM athletes
WHERE personal_best_10k = (SELECT MIN(personal_best_10k) FROM athletes);

SELECT SUM(total_time) AS total_first_place_time
FROM race_results
WHERE place = 1;

external_knowledge:
"outperformed the average in the 5K race" refers to athletes whose personal best 5K time is better than the overall average 5K time of all athletes;
"how fast they run" refers to the personal best 5K time of each athlete;
"how they compare to their teammates on average" refers to the average 5K time of all athletes on the same team as the athlete.

sql:
SELECT athlete_id, athlete_name
FROM athletes
WHERE athlete_id NOT IN (SELECT athlete_id FROM event_participants);
